#!/usr/bin/env python3
"""Rebuild coursesData.js from Python data."""
import json

courses = []

def add(code, name, credits, mode, sections, labs=None, labCredits=1):
    entry = {
        'code': code, 'name': name, 'credits': credits, 'mode': mode,
        'sections': sections
    }
    if labs:
        entry['labs'] = labs
        entry['labCredits'] = labCredits
    courses.append(entry)

# Helper: lab sections split into two back-to-back blocks (50min + 10min gap + remainder)
def split_lab(section, day, startH, startM, endH, endM, location):
    disc_end_h = startH + (startM + 50) // 60
    disc_end_m = (startM + 50) % 60
    lab_start_h = disc_end_h + (disc_end_m + 10) // 60
    lab_start_m = (disc_end_m + 10) % 60
    return {'section': section, 'meetings': [
        {'days': [day], 'startTime': f'{startH:02d}:{startM:02d}', 'endTime': f'{disc_end_h:02d}:{disc_end_m:02d}', 'location': location},
        {'days': [day], 'startTime': f'{lab_start_h:02d}:{lab_start_m:02d}', 'endTime': f'{endH:02d}:{endM:02d}', 'location': location}
    ]}

# Helper: chemistry labs have a 50-min discussion + 10-min break + remaining lab time
def chem_lab(section, day, startH, startM, endH, endM, location):
    disc_end_h = startH + (startM + 50) // 60
    disc_end_m = (startM + 50) % 60
    lab_start_h = disc_end_h + (disc_end_m + 10) // 60
    lab_start_m = (disc_end_m + 10) % 60
    return {'section': section, 'meetings': [
        {'days': [day], 'startTime': f'{startH:02d}:{startM:02d}', 'endTime': f'{disc_end_h:02d}:{disc_end_m:02d}', 'location': location},
        {'days': [day], 'startTime': f'{lab_start_h:02d}:{lab_start_m:02d}', 'endTime': f'{endH:02d}:{endM:02d}', 'location': location}
    ]}

